"use client";

import { PageHeader } from "@/components/PageHeader";
import { PageContent } from "@/features/profile/components/PageContent";
import { usePathname } from "next/navigation";

export interface ProfileTab {
  label: string;
  value: string;
  href: string;
};

export function ProfileClient() {
  const pathname = usePathname();

  const tabs: ProfileTab[] = [
    {
      label: "Personal Informations",
      value: "general",
      href: "/dashboard/profile/general",
    },
    {
      label: "Security Settings",
      value: "security",
      href: "/dashboard/profile/security",
    },
  ];

  return (
    <div className="w-full">
      <PageHeader title="Profile" description="Manage your profile." />

      <Tabs value={pathname}>
        <TabsList>
          {tabs.map((tab: ProfileTab) => (
            <TabsTrigger value={tab.value} href={tab.href}>
              {tab.label}
            </TabsTrigger>
          ))}
        </TabsList>
      </Tabs>
    </div>
  );
}
